tools.handler:
var url = getVar('jira_url');
var email = getVar('jira_email');
var token = getVar('jira_api_token');
var auth = btoa(email + ':' + token);
var max = args.max_results || 10;
var resp = httpGet(url + '/rest/api/3/search?jql=' + encodeURIComponent(args.jql) + '&maxResults=' + max, {'Authorization': 'Basic ' + auth, 'Accept': 'application/json'});
var body = resp.body;
var issues = (body.issues || []).map(function(i) {
  return {key: i.key, summary: i.fields.summary, status: i.fields.status.name, assignee: (i.fields.assignee && i.fields.assignee.displayName) || 'Unassigned', priority: (i.fields.priority && i.fields.priority.name) || '', type: i.fields.issuetype.name};
});
return JSON.stringify(issues, null, 2);

var url = getVar('jira_url');
var email = getVar('jira_email');
var token = getVar('jira_api_token');
var auth = btoa(email + ':' + token);
var payload = {fields: {project: {key: args.project_key}, summary: args.summary, issuetype: {name: args.issue_type}}};
if (args.description) payload.fields.description = {type: 'doc', version: 1, content: [{type: 'paragraph', content: [{type: 'text', text: args.description}]}]};
var resp = httpPost(url + '/rest/api/3/issue', JSON.stringify(payload), {'Authorization': 'Basic ' + auth, 'Content-Type': 'application/json', 'Accept': 'application/json'});
var issue = resp.body;
return JSON.stringify({key: issue.key, id: issue.id, url: url + '/browse/' + issue.key}, null, 2);
